// src/pages/Register.jsx
import React from 'react';

export default function Register() {
  return (
    <div style={styles.container}>
      <form style={styles.form}>
        <h2 style={styles.title}>Inscription</h2>
        <input type="text" placeholder="Nom complet" style={styles.input} />
        <input type="email" placeholder="Adresse e-mail" style={styles.input} />
        <input type="password" placeholder="Mot de passe" style={styles.input} />
        <button type="submit" style={styles.button}>Créer un compte</button>
        <p style={styles.text}>Déjà inscrit ? <a href="/login" style={styles.link}>Connexion</a></p>
      </form>
    </div>
  );
}

const styles = { ...require('./Login.jsx').default.styles };
